/*
 * DMA 循环缓冲区架构定义
 * 
 * 设计要点：
 * 1. 缓冲区大小必须是 2 的幂（便于位掩码替代取模）
 * 2. 使用 volatile 保护共享指针
 * 3. HT/TC 双中断降低最大延迟
 * 4. overflow 计数器检测消费不足
 *
 * STM32F407: DMA2 Stream5 for USART2_RX
 *   USART2 @ 115200 8N1 → ~11.5KB/s
 *   1024 字节缓冲区 ≈ 89ms 填满
 *   HT 中断在 ~44ms 时触发
 */

#include <stm32f4xx_hal.h>
#include <stdint.h>
#include <stddef.h>

#define DMA_BUF_SIZE      1024u    /* 必须是 2 的幂 */
#define DMA_BUF_MASK      (DMA_BUF_SIZE - 1u)
#define DMA_BUF_HALF      (DMA_BUF_SIZE >> 1u)  /* 512 */

/* 环形缓冲区结构 */
typedef struct {
    uint8_t  buffer[DMA_BUF_SIZE];
    volatile uint16_t head;   /* DMA 写入位置（由 DMA_SxNDTR 推算）*/
    volatile uint16_t tail;   /* CPU 读取位置 */
    volatile uint32_t overflow; /* 溢出计数 */
} dma_ring_buf_t;

/* 全局实例 */
static dma_ring_buf_t uart2_rx_buf;
static DMA_HandleTypeDef hdma_usart2_rx;
extern UART_HandleTypeDef huart2;

/*
 * 计算 DMA 写入位置
 * DMA_SxNDTR 剩余传输计数，初始为 BUFF_SIZE
 * 已传输 = BUFF_SIZE - NDTR
 * 在循环模式下，NDTR 在半传输时变为 HALF_SIZE
 */
static inline uint16_t dma_get_write_pos(void)
{
    uint32_t ndtr = hdma_usart2_rx.Instance->NDTR;
    if (ndtr > DMA_BUF_SIZE)
        return 0;
    return (uint16_t)(DMA_BUF_SIZE - ndtr);
}

/* 非阻塞读取：最多读取 avail 字节，返回实际读取数 */
size_t dma_ring_buf_read(dma_ring_buf_t *buf, uint8_t *out, size_t max_len)
{
    uint16_t w = buf->head;
    uint16_t r = buf->tail;
    size_t avail = (w >= r) ? (w - r) : (DMA_BUF_SIZE - r + w);
    size_t len = (max_len < avail) ? max_len : avail;

    for (size_t i = 0; i < len; i++) {
        out[i] = buf->buffer[r & DMA_BUF_MASK];
        r++;
    }
    buf->tail = r;
    return len;
}

/*
 * DMA 半传输回调：缓冲区前一半（0~511）已填满
 * 此时应立即处理前半部分，降低最大延迟
 */
void HAL_DMA_HalfTxCallback(DMA_HandleTypeDef *hdma)
{
    uint16_t new_head = DMA_BUF_HALF;
    uint16_t old_tail = uart2_rx_buf.tail;

    /* 检查是否溢出：如果 head 追上了 tail 超过缓冲区一半，说明消费太慢 */
    if (new_head - old_tail > DMA_BUF_HALF) {
        uart2_rx_buf.overflow++;
        /* 跳过旧数据，tail 直接追到 half 位置 */
        uart2_rx_buf.tail = new_head;
    }
}

/* DMA 传输完成回调：整个缓冲区（0~1023）已填满 */
void HAL_DMA_TxCallback(DMA_HandleTypeDef *hdma)
{
    uint16_t new_head = DMA_BUF_SIZE;
    uint16_t old_tail = uart2_rx_buf.tail;

    if (new_head - old_tail > DMA_BUF_SIZE) {
        uart2_rx_buf.overflow++;
        uart2_rx_buf.tail = new_head;
    }
}

/*
 * USART2 RX DMA 循环缓冲区初始化
 * 
 * 硬件配置：
 *   STM32F407 @ 168MHz, APB1=42MHz
 *   USART2: PA3(TX) PA2(RX), 115200 8N1
 *   DMA2 Stream5, Channel 4, USART2_RX
 *   缓冲区: 1024 字节, 循环模式
 * 
 * 寄存器映射：
 *   DMA2_Stream5 CR  = 0x40026000
 *   DMA2_Stream5 NDTR = 0x40026004
 *   USART2 CR3     = 0x40004418
 */

#include <stm32f4xx_hal.h>
#include <dma_ring_buf.h>

extern UART_HandleTypeDef huart2;
extern DMA_HandleTypeDef hdma_usart2_rx;

static void dma_usart2_rx_init(void)
{
    /*
     * 步骤 1: 清零缓冲区（可选，调试时有助于发现数据覆盖）
     * 生产环境可跳过以节省 ~1ms
     */
    for (uint16_t i = 0; i < DMA_BUF_SIZE; i++) {
        uart2_rx_buf.buffer[i] = 0xFF;
    }

    /*
     * 步骤 2: 配置 DMA Stream5
     * 对应寄存器操作（手动验证 CubeMX 生成代码）：
     *   DMA_S5CR  BIT31:30 DIR=01 (PERIPH->MEM)
     *   DMA_S5CR  BIT18    CIRC=1   (循环模式)
     *   DMA_S5CR  BIT12    MINC=1   (内存地址递增)
     *   DMA_S5CR  BIT8     PINC=0   (外设地址固定)
     *   DMA_S5CR  BIT1:0   PL=11    (最高优先级)
     *   DMA_S5PAR  写入 USART2_DR 地址 = 0x40004444
     *   DMA_S5M0AR 写入缓冲区地址
     *   DMA_S5NDTR 写入 1024
     */
    hdma_usart2_rx.Instance                 = DMA2_Stream5;
    hdma_usart2_rx.Init.Channel             = DMA_CHANNEL_4;
    hdma_usart2_rx.Init.Direction           = DMA_PERIPH_TO_MEMORY;
    hdma_usart2_rx.Init.PeriphInc           = DMA_PINC_DISABLE;
    hdma_usart2_rx.Init.MemInc              = DMA_MINC_ENABLE;
    hdma_usart2_rx.Init.PeriphDataAlignment = DMA_PDATAALIGN_BYTE;
    hdma_usart2_rx.Init.MemDataAlignment    = DMA_MDATAALIGN_BYTE;
    hdma_usart2_rx.Init.Mode                = DMA_CIRCULAR;  /* 关键：循环模式 */
    hdma_usart2_rx.Init.Priority            = DMA_PRIORITY_VERY_HIGH;
    hdma_usart2_rx.Init.FIFOMode            = DMA_FIFOMODE_DISABLE;

    hdma_usart2_rx.Instance->PAR   = (uint32_t)&huart2.Instance->DR;  /* 0x40004444 */
    hdma_usart2_rx.Instance->M0AR  = (uint32_t)uart2_rx_buf.buffer;
    hdma_usart2_rx.Instance->NDTR  = DMA_BUF_SIZE;  /* 1024 */

    /*
     * 步骤 3: 配置 DMA 中断优先级
     * NVIC_PRIO_REGISTER(DMA2_Stream5) = 4 (高于 UART 的 5)
     * 确保半传输中断不会被 UART 中断抢占太久
     */
    HAL_NVIC_SetPriority(DMA2_Stream5_IRQn, 4, 0);
    HAL_NVIC_EnableIRQ(DMA2_Stream5_IRQn);

    /*
     * 步骤 4: 启动 DMA（不带数据长度参数，循环模式下 NDTR 自动重载）
     * HAL_DMA_Start() 内部写 DMA_S5CR 的 EN=1 启动传输
     */
    HAL_DMA_Start(&hdma_usart2_rx,
                  (uint32_t)&huart2.Instance->DR,
                  (uint32_t)uart2_rx_buf.buffer,
                  DMA_BUF_SIZE);

    /*
     * 步骤 5: 使能 UART 的 DMA 接收请求
     * USART2_CR3  BIT7 DMAT=1 (发送 DMA 使能)
     * USART2_CR3  BIT6 DMAR=1 (接收 DMA 使能) ← 这行是关键
     * 
     * 注意：必须先启 DMA 再设 DMAR，否则第一个字节可能丢失！
     * 顺序反了的现象：每次复位后第一次收到的第一个字节是 0x00
     * 而不是实际发送的数据。
     */
    __HAL_UART_ENABLE_DMA(&huart2, UART_DMA_RECEIVE);

    /*
     * 步骤 6: 使能 DMA 的半传输和传输完成中断
     * DMA_S5CR  BIT3 HTIE=1 (半传输中断使能)
     * DMA_S5CR  BIT4 TCIE=1 (传输完成中断使能)
     */
    __HAL_DMA_ENABLE_IT(&hdma_usart2_rx, DMA_IT_HT);
    __HAL_DMA_ENABLE_IT(&hdma_usart2_rx, DMA_IT_TC);

    /* 初始化指针 */
    uart2_rx_buf.head = 0;
    uart2_rx_buf.tail = 0;
    uart2_rx_buf.overflow = 0;
}

/*
 * 使用示例：在 FreeRTOS 任务中消费数据
 */
void uart_consumer_task(void *arg)
{
    uint8_t local_buf[256];
    for (;;) {
        size_t n = dma_ring_buf_read(&uart2_rx_buf,
                                     local_buf,
                                     sizeof(local_buf));
        if (n > 0) {
            /* 处理 n 字节数据 */
            parse_protocol(local_buf, n);
        }
        /* 检查溢出：如果 overflow 持续增长，说明消费跟不上 */
        static uint32_t last_of = 0;
        if (uart2_rx_buf.overflow != last_of) {
            last_of = uart2_rx_buf.overflow;
            report_overflow(last_of);  /* 上报错误 */
        }
        vTaskDelay(pdMS_TO_TICKS(1));
    }
}

/*
 * 陷阱演示与修复对照
 * 
 * 错误写法 A：多次读取 NDTR，可能读到不一致的值
 */
uint16_t bad_get_head_a(void)
{
    uint32_t ndtr1 = DMA2_Stream5->NDTR;  /* 第一次读取 */
    uint32_t ndtr2 = DMA2_Stream5->NDTR;  /* 第二次读取 ← 可能不同！*/
    if (ndtr1 != ndtr2) {
        /* 竞态发生，但这里什么都没做 */
        return 0;  /* 错误：返回 0 意味着 head=1024，数据全丢了 */
    }
    return (uint16_t)(DMA_BUF_SIZE - ndtr1);
}

/* 修复 A：单次读取，存入局部变量 */
uint16_t good_get_head_a(void)
{
    volatile uint32_t ndtr = DMA2_Stream5->NDTR;  /* 一次性读取 */
    /* 如果担心 DMA 正好在写这个寄存器，可以在读取前后关 DMA 中断 */
    // __disable_irq();
    // ndtr = DMA2_Stream5->NDTR;
    // __enable_irq();
    return (uint16_t)(DMA_BUF_SIZE - ndtr);
}

/*
 * 错误写法 B：HT 回调中调用阻塞函数
 */
void HAL_DMA_HalfTxCallback_BAD(DMA_HandleTypeDef *hdma)
{
    /* 致命错误：在中断上下文中阻塞等待 UART 发送完成 */
    uint8_t half_buf[DMA_BUF_HALF];
    dma_ring_buf_read(&uart2_rx_buf, half_buf, DMA_BUF_HALF);
    HAL_UART_Transmit(&huart2, half_buf, DMA_BUF_HALF, 100);  /* 可能阻塞 1ms+ */
}

/* 修复 B：中断中只做标记，主循环处理 */
volatile uint8_t dma_ht_flag = 0;

void HAL_DMA_HalfTxCallback_GOOD(DMA_HandleTypeDef *hdma)
{
    dma_ht_flag = 1;  /* 仅设置标志，1 条指令，~60ns */
}

/* 主循环或低优先级任务中处理 */
void process_dma_data(void)
{
    if (dma_ht_flag) {
        dma_ht_flag = 0;
        uint8_t half_buf[DMA_BUF_HALF];
        dma_ring_buf_read(&uart2_rx_buf, half_buf, DMA_BUF_HALF);
        HAL_UART_Transmit(&huart2, half_buf, DMA_BUF_HALF, 100);
    }
}

/*
 * 错误写法 C：缓冲区大小不是 2 的幂
 */
#define BAD_BUF_SIZE 1000u  /* 不是 2 的幂 */
#define BAD_BUF_MASK (BAD_BUF_SIZE - 1u)  /* = 0x03E7，掩码无效！*/

uint8_t bad_read_at(dma_ring_buf_t *buf, uint16_t index)
{
    /* 这个索引计算是错误的：0x03E7 & index 不会循环到 0-999 */
    return buf->buffer[index & BAD_BUF_MASK];
}

/* 修复 C：用取模（正确但慢）或改用 2 的幂（推荐） */
uint8_t good_read_at_mod(dma_ring_buf_t *buf, uint16_t index)
{
    return buf->buffer[index % DMA_BUF_SIZE];  /* 正确但 ~15 cycles */
}

/* 修复 C'：改用 2 的幂（最佳） */
#define GOOD_BUF_SIZE 1024u  /* 2 的幂 */
#define GOOD_BUF_MASK (GOOD_BUF_SIZE - 1u)  /* = 0x03FF，完美掩码 */

uint8_t good_read_at_mask(dma_ring_buf_t *buf, uint16_t index)
{
    return buf->buffer[index & GOOD_BUF_MASK];  /* 1 条 AND 指令 */
}

/*
 * 重构前：散落的裸全局变量（坏味道：数据泥棒 + 依恋情结）
 * 
 * 问题：
 * 1. head/tail/buffer/overflow 四处散落，任何人可修改
 * 2. available 计算逻辑重复 3 次
 * 3. DMA 回调直接操作 buffer，绕过了所有安全检查
 * 4. 缓冲区大小硬编码在各处
 */

/* ===== 重构前 ===== */
static uint8_t rx_buffer[1024];  /* 硬编码大小 */
static volatile uint16_t rx_head = 0;
static volatile uint16_t rx_tail = 0;
static volatile uint32_t rx_overflow = 0;

/* 计算可用字节——这段代码在三个地方重复 */
static uint16_t calc_available_bad(void)
{
    if (rx_head >= rx_tail)
        return rx_head - rx_tail;
    else
        return 1024 - rx_tail + rx_head;  /* 硬编码 1024 */
}

/* 读取数据——直接访问裸 buffer */
void consume_bad(void)
{
    uint16_t avail = calc_available_bad();
    for (uint16_t i = 0; i < avail; i++) {
        uint8_t byte = rx_buffer[(rx_tail + i) % 1024];  /* 又一个硬编码 */
        uart_send_byte(byte);
    }
    rx_tail = (rx_tail + avail) % 1024;
}

/* DMA 回调——直接操作 buffer，跳过所有检查 */
void HAL_DMA_HalfTxCallback_BAD(void)
{
    rx_head = 512;  /* 直接赋值，没有边界检查 */
    /* 如果此时 consume_bad 正在读 rx_buffer[511]，数据不一致 */
}


