/* 头文件：dma_ring_buf.h */
#ifndef DMA_RING_BUF_H
#define DMA_RING_BUF_H

#include <stdint.h>
#include <stddef.h>

#define DMA_RING_BUF_DEFAULT_SIZE  1024u

typedef struct {
    uint8_t  *buffer;
    uint16_t  size;       /* 缓冲区大小（2 的幂）*/
    uint16_t  mask;       /* size - 1，用于位掩码 */
    volatile uint16_t head;
    volatile uint16_t tail;
    volatile uint32_t overflow;
} dma_ring_buf_t;

/* 公共 API */
void   dma_ring_buf_init(dma_ring_buf_t *rb, uint8_t *buf, uint16_t size);
size_t dma_ring_buf_read(dma_ring_buf_t *rb, uint8_t *out, size_t max);
size_t dma_ring_buf_available(dma_ring_buf_t *rb);
void   dma_ring_buf_clear(dma_ring_buf_t *rb);
uint32_t dma_ring_buf_get_overflow(dma_ring_buf_t *rb);

#endif

/* 实现文件：dma_ring_buf.c */
#include "dma_ring_buf.h"

void dma_ring_buf_init(dma_ring_buf_t *rb, uint8_t *buf, uint16_t size)
{
    rb->buffer  = buf;
    rb->size    = size;
    rb->mask    = size - 1u;           /* 必须是 2 的幂 */
    rb->head    = 0;
    rb->tail    = 0;
    rb->overflow = 0;
}

size_t dma_ring_buf_available(dma_ring_buf_t *rb)
{
    uint16_t h = rb->head;
    uint16_t t = rb->tail;
    if (h >= t)
        return (size_t)(h - t);
    return (size_t)(rb->size - t + h);
}

size_t dma_ring_buf_read(dma_ring_buf_t *rb, uint8_t *out, size_t max)
{
    size_t avail = dma_ring_buf_available(rb);
    size_t len   = (max < avail) ? max : avail;

    for (size_t i = 0; i < len; i++) {
        out[i] = rb->buffer[(rb->tail + i) & rb->mask];  /* 位掩码替代取模 */
    }
    rb->tail = (uint16_t)((rb->tail + (uint16_t)len) & rb->mask);
    return len;
}

void dma_ring_buf_clear(dma_ring_buf_t *rb)
{
    rb->tail = rb->head;
}

uint32_t dma_ring_buf_get_overflow(dma_ring_buf_t *rb)
{
    return rb->overflow;
}

/* DMA 回调——现在只通过 API 操作，安全且可维护 */
extern dma_ring_buf_t uart2_rx_buf;

void HAL_DMA_HalfTxCallback_GOOD(DMA_HandleTypeDef *hdma)
{
    uint16_t new_head = uart2_rx_buf.size >> 1;
    if ((int16_t)(new_head - uart2_rx_buf.tail) > (int16_t)(uart2_rx_buf.size >> 1)) {
        uart2_rx_buf.overflow++;
        uart2_rx_buf.tail = new_head;
    }
    uart2_rx_buf.head = new_head;
}
